 1	import React, { FC, memo, ReactNode, useState } from 'react';
 2	import { CopyToClipboard as CTC } from 'react-copy-to-clipboard';
 3	import * as _ from 'lodash';
 4	
 5	import { Button, CodeBlock, CodeBlockAction, CodeBlockCode, Tooltip } from '@patternfly/react-core';
 6	import { CopyIcon } from '@patternfly/react-icons';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	
 9	export type CopyToClipboardProps = {
10	  value: string;
11	  visibleValue?: ReactNode;
12	};
13	
14	export const CopyToClipboard: FC<CopyToClipboardProps> = memo((props) => {
15	  const { t } = useNetworkingTranslation();
16	  const [copied, setCopied] = useState(false);
17	
18	  const tooltipText = copied ? t('Copied') : t('Copy to clipboard');
19	  const tooltipContent = [
20	    <span className="co-nowrap" key="nowrap">
21	      {tooltipText}
22	    </span>,
23	  ];
24	
25	  // Default to value if no visible value was specified.
26	  const visibleValue = _.isNil(props.visibleValue) ? props.value : props.visibleValue;
27	
28	  const actions = (
29	    <CodeBlockAction>
30	      <Tooltip content={tooltipContent} exitDelay={1250} trigger="click mouseenter focus">
31	        <CTC onCopy={() => setCopied(true)} text={props.value}>
32	          <Button
33	            className="co-copy-to-clipboard__btn"
34	            onMouseEnter={() => setCopied(false)}
35	            type="button"
36	            variant="plain"
37	          >
38	            <CopyIcon />
39	            <span className="pf-v6-u-screen-reader">{t('Copy to clipboard')}</span>
40	          </Button>
41	        </CTC>
42	      </Tooltip>
43	    </CodeBlockAction>
44	  );
45	
46	  return (
47	    <CodeBlock actions={actions} className="co-copy-to-clipboard">
48	      <CodeBlockCode
49	        className="co-copy-to-clipboard__text"
50	        codeClassName="co-copy-to-clipboard__code"
51	        data-test="copy-to-clipboard"
52	      >
53	        {visibleValue}
54	      </CodeBlockCode>
55	    </CodeBlock>
56	  );
57	});

